text:
{
  "formal_minutes": {
    "회의정보": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"]
    },
    "확정_결정": [
      {
        "id": "D1",
        "내용": "공개 릴리스 목표 시각은 금요일 15:00 KST이며, 전제 조건은 smoke test 통과이다."
      },
      {
        "id": "D2",
        "내용": "packageName mismatch 발생 시 먼저 package config를 점검하고, 계약(contract) 자체가 잘못된 경우에만 smoke-theme-pack.mjs를 검토한다."
      }
    ],
    "반려된_제안": [
      {
        "id": "R1",
        "내용": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경하자는 제안은 반려되었다."
      }
    ],
    "내부_스트레치_목표": [
      {
        "id": "S1",
        "내용": "수요일 릴리스 제안은 내부 스트레치 목표로만 남았고 확정 일정이 아니다."
      }
    ],
    "비결정_사항": [
      {
        "id": "N1",
        "내용": "README 설치 절차는 가능하면 목요일까지 검토 필요 의견이 있었으나 담당자 미지정 상태다."
      }
    ],
    "리스크": [
      {
        "id": "K1",
        "내용": "tarball 경로 오류 시 릴리스 지연 가능"
      },
      {
        "id": "K2",
        "내용": "README 설치 절차가 오래된 경우 릴리스 노트가 사용자에게 오해를 줄 가능성"
      }
    ],
    "오픈_질문": [
      {
        "id": "Q1",
        "내용": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "id": "Q2",
        "내용": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 smoke test 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 smoke 결과 공유 이후 생성된 tarball 경로 점검",
      "due": "미정",
      "status": "선행조건 대기",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 단계 검토(가능하면 목요일)",
      "due": "목요일(가능 시)",
      "status": "담당자 미지정",
      "source_certainty": "suggested_not_assigned"
    }
  ],
  "followup_note": {
    "다음_확인사항": [
      "금요일 10:00 KST smoke test 결과 수신 여부",
      "금요일 12:00 KST action_items.md 트리아지 노트 작성 완료 여부",
      "smoke 결과 이후 Hara의 tarball 경로 점검 결과",
      "최종 릴리스 승인 권한자 확정",
      "릴리스 노트에 내부 수요일 스트레치 목표를 포함할지 결정",
      "README 설치 절차 검토 담당자 지정 여부"
    ],
    "작성_가드레일": [
      "확정 사실과 제안/미결 사항을 분리해 기록",
      "수요일 릴리스는 확정 일정으로 표기하지 않음",
      "반려된 제안을 실행 결정처럼 기록하지 않음",
      "담당자·기한 미정 항목은 미정으로 명시"
    ]
  },
  "non_invention_rules": [
    "고객명 또는 외부 파트너를 새로 만들지 않는다.",
    "예산 수치/예산 승인 사실을 만들지 않는다.",
    "보안 사고, 운영 장애(프로덕션 아웃티지) 사실을 만들지 않는다.",
    "법무 승인 필요 사실을 만들지 않는다.",
    "명시되지 않은 owner와 deadline을 임의로 확정하지 않는다.",
    "주어진 공개 합성 픽스처 밖의 근거를 추가하지 않는다."
  ]
}
